const SULTAN_ORDER_OPTION_COUNT = 4;
function buildSultanOrderQuestions() {
  return SULTAN_ORDER_DATA.map((sultan) => {
    const pool = SULTAN_ORDER_DATA.filter((item) => item.id !== sultan.id),
      decoys = shuffleArray([...pool]).slice(0, SULTAN_ORDER_OPTION_COUNT - 1),
      options = shuffleArray([sultan, ...decoys]).map((item) => ({ ...item }));
    return {
      id: `sultan-${sultan.order}`,
      promptOrder: sultan.order,
      correctOptionId: sultan.id,
      correctSultan: { ...sultan },
      options,
      label: `${sultan.order}. padişah`,
    };
  });
}
function getSultanQuestionFeedback(game) {
  return Array.isArray(game?.answerStates) ? game.answerStates[game.currentQuestion] : null;
}
async function startSultanOrderGame() {
  const allQuestions = buildSultanOrderQuestions(),
    setup = await requestGameSetup(allQuestions.length);
  if (!setup) return void renderHome();
  stopGeographyMusic(),
    stopAviationMusic(),
    setTopbar("👑 Padişah Sıralama", "36 padişahı baştan sona doğru sırayla bul", "center"),
    setFullscreenButtonVisible(!1);
  const selectedQuestions = setup.questionLimit === 1 / 0
      ? [...allQuestions]
      : allQuestions.slice(0, Math.min(setup.questionLimit, allQuestions.length));
  currentGame = {
    type: "sultanorder",
    sourceQuestions: [...allQuestions],
    questions: selectedQuestions.map((question) => ({
      ...question,
      correctSultan: { ...question.correctSultan },
      options: question.options.map((option) => ({ ...option })),
    })),
    currentQuestion: 0,
    score: 0,
    selectedAnswers: new Array(selectedQuestions.length).fill(null),
    answerStates: new Array(selectedQuestions.length).fill(null),
    playerName: setup.playerName,
    questionLimit: setup.questionLimit,
    isInfinite: setup.isInfinite,
    highScore: getHighScore("sultanorder"),
  };
  startUniversalMusic("sultanorder"), renderSultanOrderGame();
}
function renderSultanOrderGame() {
  const game = currentGame,
    question = game.questions[game.currentQuestion],
    selected = game.selectedAnswers[game.currentQuestion],
    answered = isAnsweredValue(selected),
    answerState = getSultanQuestionFeedback(game);
  appScreen.innerHTML = `
    <div class="game-toolbar">
      <button type="button" class="secondary-btn menu-btn" id="back-home">← Menü</button>
      <div class="toolbar-badge">👑 Padişah Sıralama</div>
    </div>

    ${renderUniversalMusicBar("sultanorder")}

    ${renderStatsRow(game)}

    <div class="progress-area">
      <div class="progress-bar">
        <div class="progress-fill" style="width:${getQuestionProgressPercent(game)}%"></div>
      </div>
    </div>

    <section class="question-card sultan-order-card">
      <h2>Osmanlı Devleti'nin ${question.promptOrder}. padişahı kimdir?</h2>
      <div class="sultan-order-subtitle">Doğru padişahı 4 şık arasından seç. Oyun 1. padişahtan 36. padişaha kadar ilerler.</div>

      <div class="answers" id="answers-container"></div>
    </section>

    ${renderQuestionNav(game, "Testi Bitir")}
  `;
  const answersContainer = document.getElementById("answers-container");
  question.options.forEach((option) => {
    const button = document.createElement("button"),
      isSelected = selected === option.id,
      isCorrect = answered && option.id === question.correctOptionId,
      isWrongSelection = answered && isSelected && option.id !== question.correctOptionId;
    button.type = "button";
    button.className = `answer-btn ${isSelected ? "selected" : ""} ${isCorrect ? "correct" : ""} ${isWrongSelection ? "wrong" : ""}`.trim();
    button.disabled = answered;
    button.innerHTML = `<strong>${option.name}</strong>`;
    button.addEventListener("click", () => {
      if (answered) return;
      const correct = option.id === question.correctOptionId;
      game.selectedAnswers[game.currentQuestion] = option.id;
      game.answerStates[game.currentQuestion] = correct ? "correct" : "wrong";
      correct ? (playCorrectSound(), game.score += 10) : (playWrongSound(), game.score -= 5);
      updateHighScore(game);
      renderSultanOrderGame();
      scheduleAutoAdvance(game, renderSultanOrderGame, renderSultanOrderResult, correct);
    });
    answersContainer.appendChild(button);
  });
  document.getElementById("back-home").addEventListener("click", () => {
    stopUniversalMusic(), renderHome();
  });
  bindUniversalMusicControls("sultanorder");
  bindAutoAdvanceToggle();
  const prevBtn = document.getElementById("prev-btn");
  prevBtn && prevBtn.addEventListener("click", () => {
    game.currentQuestion > 0 && (game.currentQuestion--, renderSultanOrderGame());
  });
  const nextBtn = document.getElementById("next-btn");
  nextBtn && nextBtn.addEventListener("click", () => handleNextQuestion(game, renderSultanOrderGame, renderSultanOrderResult));
  const skipBtn = document.getElementById("skip-btn");
  skipBtn && skipBtn.addEventListener("click", () => {
    game.answerStates[game.currentQuestion] = "skipped";
    handleSkipQuestion(game, renderSultanOrderGame, renderSultanOrderResult);
  });
  const finishBtn = document.getElementById("finish-btn");
  finishBtn && finishBtn.addEventListener("click", (event) => {
    event.preventDefault(), event.stopPropagation(), renderSultanOrderResult();
  });
}
function renderSultanOrderResult() {
  clearAnswerAdvanceTimer();
  const game = currentGame;
  updateHighScore(game);
  const maxScore = 10 * game.questions.length;
  let message = "Taht sıralamasını biraz daha tekrar edersen seri şekilde çözersin.";
  game.score === maxScore
    ? message = "Muhteşem. 36 padişahın kronolojik akışı sende oturmuş."
    : game.score >= .6 * maxScore && (message = "Gayet iyi. Osmanlı taht sırasını büyük ölçüde biliyorsun.");
  appScreen.innerHTML = renderResultSummary("Padişah Sıralama Tamamlandı", game, maxScore, message, "restart-sultanorder");
  const restartBtn = document.getElementById("restart-sultanorder");
  restartBtn && restartBtn.addEventListener("click", startSultanOrderGame),
    document.getElementById("back-home").addEventListener("click", () => {
      stopUniversalMusic(), renderHome();
    });
}


